// Extract and normalize alert data
// Supports Alertmanager format and generic webhook format

const items = [];

for (const item of $input.all()) {
  const raw = item.json.body || item.json;

  let source = 'unknown';
  let type = 'generic';
  let message = '';
  let severity = 'info';
  let labels = {};
  let rawPayload = raw;

  // --- Alertmanager format ---
  // Alertmanager sends { alerts: [ { status, labels, annotations, ... } ] }
  if (raw.alerts && Array.isArray(raw.alerts)) {
    for (const alert of raw.alerts) {
      const alertLabels = alert.labels || {};
      const annotations = alert.annotations || {};

      source = 'alertmanager';
      type = alertLabels.alertname || alertLabels.type || 'prometheus-alert';
      severity = alertLabels.severity || alert.status || 'warning';
      message = annotations.summary
        || annotations.description
        || annotations.message
        || `${type}: ${alertLabels.instance || 'unknown instance'}`;

      items.push({
        json: {
          source,
          type,
          message,
          severity,
          labels: alertLabels,
          status: alert.status || 'firing',
          startsAt: alert.startsAt || new Date().toISOString(),
          receivedAt: new Date().toISOString(),
          rawPayload: alert
        }
      });
    }
    return items;
  }

  // --- Generic webhook format ---
  // Expects: { source, type, message, severity, ... }
  source = raw.source || raw.Source || raw.origin || 'unknown';
  type = raw.type || raw.Type || raw.event || raw.alertname || 'generic';
  message = raw.message || raw.Message || raw.msg || raw.text || raw.description || JSON.stringify(raw).substring(0, 500);
  severity = raw.severity || raw.Severity || raw.level || raw.priority || 'info';
  labels = raw.labels || {};

  // --- n8n internal event format ---
  if (raw.executionId || raw.workflowId) {
    source = 'n8n';
    type = raw.event || (raw.success === false ? 'workflow_failure' : 'workflow_event');
    message = raw.message || `Workflow ${raw.workflowName || raw.workflowId || 'unknown'}: ${type}`;
    severity = raw.success === false ? 'error' : (raw.severity || 'info');
  }

  items.push({
    json: {
      source,
      type,
      message,
      severity,
      labels,
      status: raw.status || 'firing',
      startsAt: raw.startsAt || raw.timestamp || new Date().toISOString(),
      receivedAt: new Date().toISOString(),
      rawPayload
    }
  });
}

return items;

// Deterministic scoring — no LLM needed
//
// Score 5 (Critical): Service down > 5 min, LXC/container crashed, Gateway unreachable
// Score 4 (High):     Disk > 85%, GPU temp > 85C, Workflow failure, Job match > 80
// Score 3 (Medium):   Escalation rate > 25%, API cost > $10/day, High-priority email
// Score 2 (Low):      Transient CPU spikes, Watchtower updates, Scheduled restarts
// Score 1 (Noise):    Successful routine runs, Brief latency spikes

const items = [];

for (const item of $input.all()) {
  const { source, type, message, severity, labels, status } = item.json;

  const msgLower = (message || '').toLowerCase();
  const typeLower = (type || '').toLowerCase();
  const sevLower = (severity || '').toLowerCase();
  const combined = `${typeLower} ${msgLower} ${sevLower}`;

  let score = 1;
  let reason = 'Default: noise / routine';

  // ── Score 5 (Critical) ──────────────────────────────────
  // Service down > 5 min
  if (/service.*(down|unreachable|offline)/i.test(combined) && !/resolved|recovering/i.test(combined)) {
    score = 5;
    reason = 'Service down or unreachable';
  }
  // LXC / container crashed
  else if (/lxc.*(crash|stopped|dead|fail)|container.*(crash|oom|killed|exited)/i.test(combined)) {
    score = 5;
    reason = 'LXC or container crashed';
  }
  // Gateway unreachable
  else if (/gateway.*(unreachable|down|timeout|fail)/i.test(combined)) {
    score = 5;
    reason = 'Gateway unreachable';
  }
  // Severity critical from Alertmanager
  else if (sevLower === 'critical' || sevLower === 'fatal') {
    score = 5;
    reason = `Severity marked as ${severity}`;
  }
  // Node down
  else if (/node.*(down|unreachable|offline)/i.test(combined)) {
    score = 5;
    reason = 'Node down';
  }

  // ── Score 4 (High) ──────────────────────────────────────
  // Disk > 85%
  else if (/disk/i.test(combined)) {
    const pctMatch = combined.match(/(\d+)\s*%/);
    if (pctMatch && parseInt(pctMatch[1], 10) > 85) {
      score = 4;
      reason = `Disk usage ${pctMatch[1]}% (>85%)`;
    } else if (/full|critical|high/i.test(combined)) {
      score = 4;
      reason = 'Disk usage high';
    }
  }
  // GPU temp > 85C
  else if (/gpu.*(temp|thermal)/i.test(combined)) {
    const tempMatch = combined.match(/(\d+)\s*[°c]/i) || combined.match(/temp.*?(\d+)/i);
    if (tempMatch && parseInt(tempMatch[1], 10) > 85) {
      score = 4;
      reason = `GPU temperature ${tempMatch[1]}C (>85C)`;
    }
  }
  // Workflow failure
  else if (/workflow.*(fail|error|crash)|execution.*fail/i.test(combined) || (source === 'n8n' && typeLower.includes('failure'))) {
    score = 4;
    reason = 'Workflow failure';
  }
  // Job match > 80
  else if (/job.*(match|score)/i.test(combined)) {
    const scoreMatch = combined.match(/score.*?(\d+)/);
    if (scoreMatch && parseInt(scoreMatch[1], 10) > 80) {
      score = 4;
      reason = `Job match score ${scoreMatch[1]} (>80)`;
    }
  }
  // Severity warning/error from Alertmanager
  else if (sevLower === 'error' || sevLower === 'high') {
    score = 4;
    reason = `Severity marked as ${severity}`;
  }

  // ── Score 3 (Medium) ────────────────────────────────────
  // Escalation rate > 25%
  else if (/escalat/i.test(combined)) {
    const rateMatch = combined.match(/(\d+)\s*%/);
    if (rateMatch && parseInt(rateMatch[1], 10) > 25) {
      score = 3;
      reason = `Escalation rate ${rateMatch[1]}% (>25%)`;
    } else {
      score = 3;
      reason = 'Escalation detected';
    }
  }
  // API cost > $10/day
  else if (/api.*(cost|spend|bill)/i.test(combined)) {
    const costMatch = combined.match(/\$?(\d+\.?\d*)/);
    if (costMatch && parseFloat(costMatch[1]) > 10) {
      score = 3;
      reason = `API cost $${costMatch[1]}/day (>$10)`;
    }
  }
  // High-priority email
  else if (/email.*(urgent|high.?pri|important)/i.test(combined) || /high.?pri.*email/i.test(combined)) {
    score = 3;
    reason = 'High-priority email notification';
  }
  // Severity warning
  else if (sevLower === 'warning' || sevLower === 'medium') {
    score = 3;
    reason = `Severity marked as ${severity}`;
  }

  // ── Score 2 (Low) ───────────────────────────────────────
  // Transient CPU spikes
  else if (/cpu.*(spike|burst|transient|high)/i.test(combined)) {
    score = 2;
    reason = 'Transient CPU spike';
  }
  // Watchtower updates
  else if (/watchtower|image.*(update|pull)/i.test(combined)) {
    score = 2;
    reason = 'Watchtower container update';
  }
  // Scheduled restarts
  else if (/schedul.*(restart|reboot|maintenance)/i.test(combined)) {
    score = 2;
    reason = 'Scheduled restart/maintenance';
  }
  // Info severity
  else if (sevLower === 'info' || sevLower === 'low') {
    score = 2;
    reason = `Severity marked as ${severity}`;
  }

  // ── Score 1 (Noise) ─────────────────────────────────────
  // Successful routine runs
  else if (/success|complet|ok|pass|healthy|resolved/i.test(combined)) {
    score = 1;
    reason = 'Successful / resolved routine event';
  }
  // Brief latency spikes
  else if (/latency.*(spike|brief|transient)/i.test(combined)) {
    score = 1;
    reason = 'Brief latency spike';
  }

  // Map score to label
  const scoreLabels = {
    5: 'Critical',
    4: 'High',
    3: 'Medium',
    2: 'Low',
    1: 'Noise'
  };

  items.push({
    json: {
      ...item.json,
      score,
      scoreLabel: scoreLabels[score] || 'Unknown',
      scoreReason: reason
    }
  });
}

return items;

// Time-of-day gating
//
// 22:00 - 07:00 (night) → only push score 5 (Critical)
// 07:00 - 22:00 (day)   → push score 4-5 (High + Critical)
//
// All notifications pass through to the log regardless.
// This node adds: shouldPush (boolean), pushThreshold (int), currentHour (int)

const items = [];

for (const item of $input.all()) {
  const now = new Date();
  // Adjust for local timezone (US Central = UTC-6, adjust as needed)
  // Using the server's local time via getHours()
  const currentHour = now.getHours();

  const isNightMode = (currentHour >= 22 || currentHour < 7);
  const pushThreshold = isNightMode ? 5 : 4;

  const score = item.json.score || 1;
  const shouldPush = score >= pushThreshold;

  items.push({
    json: {
      ...item.json,
      shouldPush,
      pushThreshold,
      currentHour,
      timeMode: isNightMode ? 'night (22:00-07:00)' : 'day (07:00-22:00)'
    }
  });
}

return items;

// Log ALL notifications (both pushed and suppressed) for future SQLite integration
//
// Schema for notifications table:
//   id INTEGER PRIMARY KEY AUTOINCREMENT,
//   source TEXT,
//   type TEXT,
//   message TEXT,
//   severity TEXT,
//   score INTEGER,
//   score_label TEXT,
//   score_reason TEXT,
//   should_push BOOLEAN,
//   push_threshold INTEGER,
//   time_mode TEXT,
//   current_hour INTEGER,
//   status TEXT,
//   received_at TEXT,
//   logged_at TEXT
//
// To enable SQLite: replace this Code node with an n8n SQLite node
// or HTTP Request to a logging API.

const items = [];

for (const item of $input.all()) {
  const logEntry = {
    source: item.json.source || 'unknown',
    type: item.json.type || 'generic',
    message: (item.json.message || '').substring(0, 1000),
    severity: item.json.severity || 'info',
    score: item.json.score || 0,
    scoreLabel: item.json.scoreLabel || 'Unknown',
    scoreReason: item.json.scoreReason || '',
    shouldPush: item.json.shouldPush || false,
    pushThreshold: item.json.pushThreshold || 4,
    timeMode: item.json.timeMode || 'unknown',
    currentHour: item.json.currentHour || -1,
    status: item.json.status || 'unknown',
    receivedAt: item.json.receivedAt || new Date().toISOString(),
    loggedAt: new Date().toISOString(),
    pushed: item.json.shouldPush || false
  };

  // Log to n8n execution output (visible in execution history)
  console.log(JSON.stringify({
    event: 'notification_logged',
    ...logEntry
  }));

  items.push({
    json: {
      status: 'logged',
      ...logEntry
    }
  });
}

return items;
